const topic = $.input.topic;
const scriptType = $.input.scriptType || 'narration';
const duration = $.input.duration || '60 seconds';
const voiceStyle = $.input.voiceStyle || 'warm and conversational';

let prompt = 'You are an expert voice script writer specializing in text-to-speech content. Write a script optimized for spoken delivery.\n\n';
prompt += 'TOPIC: ' + topic + '\n';
prompt += 'SCRIPT TYPE: ' + scriptType + '\n';
prompt += 'TARGET DURATION: ' + duration + '\n';
prompt += 'VOICE STYLE: ' + voiceStyle + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write for the ear, not the eye — use short sentences and natural rhythm\n';
prompt += '- Include pause markers [PAUSE] where the speaker should breathe\n';
prompt += '- Avoid abbreviations, spell out numbers\n';
prompt += '- Use emphasis markers *word* for words to stress\n';
prompt += '- Include pronunciation guides for unusual words in (parentheses)\n';
prompt += '- Estimate word count and speaking time at ~150 words per minute\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "Script title",\n';
prompt += '  "script": "The full voice script with pause markers and emphasis",\n';
prompt += '  "wordCount": 150,\n';
prompt += '  "estimatedDuration": "60 seconds",\n';
prompt += '  "scriptType": "narration",\n';
prompt += '  "voiceDirection": "Notes for voice talent on delivery",\n';
prompt += '  "keyPhrases": ["important phrases to emphasize"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Voice Script', script: raw, wordCount: 0, estimatedDuration: 'unknown', scriptType: 'narration', voiceDirection: '', keyPhrases: [] }; }

const ai = $.steps.parseAI.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Voice Script Ready', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (ai.title || 'Voice Script') + '*' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Type:*\n' + (ai.scriptType || 'narration') },
  { type: 'mrkdwn', text: '*Duration:*\n' + (ai.estimatedDuration || 'N/A') }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Word Count:*\n' + (ai.wordCount || 0) },
  { type: 'mrkdwn', text: '*Key Phrases:*\n' + (ai.keyPhrases || []).slice(0, 3).join(', ') }
] });
blocks.push({ type: 'divider' });

if (ai.voiceDirection) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:studio_microphone: Voice Direction:*\n' + ai.voiceDirection.slice(0, 500) } });
  blocks.push({ type: 'divider' });
}

const scriptText = (ai.script || 'No script generated.').slice(0, 2800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Script:*\n```' + scriptText + '```' } });

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI + One CLI | Optimized for TTS delivery' }] });

const fallback = 'Voice Script: ' + (ai.title || 'Script') + ' (' + (ai.estimatedDuration || '') + ') - ' + (ai.wordCount || 0) + ' words';
return { blocks, fallback };
